import { readFile, writeFile } from "node:fs/promises";
import { fileURLToPath } from "node:url";
const files = {
  registry: new URL("../src/prompt-blueprint.js", import.meta.url),
  history: new URL("../src/history-store.js", import.meta.url),
  imageGeneration: new URL("../src/image-generation.js", import.meta.url),
  app: new URL("../app.js", import.meta.url),
  output: new URL("../app.bundle.js", import.meta.url)
};

const [registrySource, historySource, imageGenerationSource, appSource] = await Promise.all([
  readFile(files.registry, "utf8"),
  readFile(files.history, "utf8"),
  readFile(files.imageGeneration, "utf8"),
  readFile(files.app, "utf8")
]);

function removeExports(source) {
  return source.replace(/^export\s+/gm, "");
}

const appWithoutImports = appSource.replace(/^import\s+.+?;\s*$/gm, "").trimStart();
const bundle = `/* Generated by scripts/build-browser-bundle.mjs. Edit app.js or src/, then rebuild. */
(() => {
"use strict";

${removeExports(registrySource)}
${removeExports(historySource)}
${removeExports(imageGenerationSource)}
${appWithoutImports}
})();
`;

await writeFile(files.output, bundle);
console.log("Built app.bundle.js");
